function solve(nums, k) {
    nums.sort((a, b) => a - b);
    let n = nums.length;
    let minRemovals = n - 1; // Initialize with the worst case (keeping only one element)

    for (let i = 0; i < n; i++) {
        let left = i;
        let right = n - 1;
        let bestJ = i;

        while (left <= right) {
            let mid = Math.floor((left + right) / 2);
            if (nums[mid] <= nums[i] * k) {
                bestJ = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        let currentRemovals = n - (bestJ - i + 1);
        if (currentRemovals < minRemovals) {
            minRemovals = currentRemovals;
        }
    }

    return minRemovals;
}

